#include "kernel_operator.h"
using namespace AscendC;

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00285Custom {
public:
    __aicore__ inline KernelCa6k00285Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t N, uint32_t C_in, uint32_t H_in, uint32_t W_in,
                                uint32_t C_out, uint32_t H_out, uint32_t W_out,
                                uint32_t factor, uint32_t totalLength, uint32_t tileLength)
    {
        N_ = N;
        C_in_ = C_in;
        H_in_ = H_in;
        W_in_ = W_in;
        C_out_ = C_out;
        H_out_ = H_out;
        W_out_ = W_out;
        factor_ = factor;
        totalLen_ = totalLength;
        tileLen_ = tileLength;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(tmpBuf_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        // Single-core: iterate over output elements and map back to input.
        uint32_t cnt = 0;
        for (uint32_t n = 0; n < N_; ++n) {
            for (uint32_t co = 0; co < C_out_; ++co) {
                uint32_t g = co / (factor_ * factor_);
                uint32_t offset = co % (factor_ * factor_);
                uint32_t offset_y = offset / factor_;
                uint32_t offset_x = offset % factor_;
                for (uint32_t h = 0; h < H_out_; ++h) {
                    for (uint32_t w = 0; w < W_out_; ++w, ++cnt) {
                        uint32_t in_h = h * factor_ + offset_y;
                        uint32_t in_w = w * factor_ + offset_x;
                        uint32_t in_idx = ((n * C_in_ + g) * H_in_ + in_h) * W_in_ + in_w;
                        float val = xGm_.GetValue(in_idx);
                        yGm_.SetValue(cnt, val);
                    }
                }
            }
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> tmpBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t N_;
    uint32_t C_in_;
    uint32_t H_in_;
    uint32_t W_in_;
    uint32_t C_out_;
    uint32_t H_out_;
    uint32_t W_out_;
    uint32_t factor_;
    uint32_t totalLen_;
    uint32_t tileLen_;
};

extern "C" __global__ __aicore__ void ca6k_00285_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00285Custom op;
    op.Init(x, y,
            tiling_data.N, tiling_data.C_in, tiling_data.H_in, tiling_data.W_in,
            tiling_data.C_out, tiling_data.H_out, tiling_data.W_out,
            tiling_data.factor, tiling_data.totalLength, tiling_data.tileLength);
    op.Process();
}
